'use strict';

const TransportSubstrate = (() => {

    const _state     = new Map();
    const _listeners = new Map();
    const _history   = [];
    const MAX_HISTORY = 100;

    function _emit(event, data) {
        const ls = _listeners.get(event);
        if (!ls) return;
        for (const { handler } of ls) {
            try { handler(data); } catch (e) { console.error(`[Transport L4] ${event}:`, e); }
        }
    }

    function _record(action, key, oldVal, newVal) {
        _history.push({ t: Date.now(), action, key, oldVal, newVal });
        if (_history.length > MAX_HISTORY) _history.shift();
    }


    function zxy2(x, y) { return x * y * y; }


    const _metrics = {
        sets: 0, gets: 0, deletes: 0,
        transactions: 0, errors: 0,
        snapshots: 0, restores: 0,
        saves: 0, loads: 0,
        startTime: Date.now()
    };





    function set(key, value, silent = false) {
        _metrics.sets++;
        const old = _state.get(key);
        if (old === value) return value;
        _state.set(key, value);
        _record('set', key, old, value);
        if (!silent) {
            _emit('change', { key, oldValue: old, newValue: value });
            _emit(`change:${key}`, { oldValue: old, newValue: value });
        }
        return value;
    }

    function get(key, def = null) { _metrics.gets++; return _state.has(key) ? _state.get(key) : def; }
    function has(key)             { return _state.has(key); }

    function del(key) {
        if (!_state.has(key)) return false;
        _metrics.deletes++;
        const old = _state.get(key);
        _state.delete(key);
        _record('delete', key, old, undefined);
        _emit('delete', { key, oldValue: old });
        return true;
    }

    function clear(silent = false) {
        const snap = getAll();
        _state.clear();
        _record('clear', null, snap, null);
        if (!silent) _emit('clear', { oldState: snap });
    }

    function getAll() {
        const o = {};
        for (const [k, v] of _state) o[k] = v;
        return o;
    }

    function setAll(values, silent = false) {
        for (const [k, v] of Object.entries(values)) set(k, v, silent);
    }





    function computed(key, fn, deps = []) {
        set(key, fn({ get, has, getAll }), true);
        deps.forEach(d => on(`change:${d}`, () => set(key, fn({ get, has, getAll }))));
    }

    function watch(keys, handler) {
        return keys.map(k => on(`change:${k}`, handler));
    }





    let _lid = 0;
    function on(event, handler) {
        if (!_listeners.has(event)) _listeners.set(event, []);
        const id = `tl_${_lid++}`;
        _listeners.get(event).push({ id, handler });
        return id;
    }

    function off(id) {
        for (const [ev, ls] of _listeners) {
            const i = ls.findIndex(l => l.id === id);
            if (i !== -1) { ls.splice(i, 1); if (!ls.length) _listeners.delete(ev); return true; }
        }
        return false;
    }

    function once(event, handler) {
        const id = on(event, data => { handler(data); off(id); });
        return id;
    }





    function history(limit = 10)  { return _history.slice(-limit); }
    function clearHistory()       { _history.length = 0; }
    function snapshot()           { _metrics.snapshots++; return { t: Date.now(), state: getAll() }; }
    function restore(snap, silent = false) { _metrics.restores++; clear(true); setAll(snap.state, silent); if (!silent) _emit('restore', { snap }); }

    function save(storageKey, keys = null) {
        _metrics.saves++;
        if (typeof localStorage === 'undefined') return false;
        const data = keys ? keys.reduce((o, k) => { if (has(k)) o[k] = get(k); return o; }, {}) : getAll();
        try { localStorage.setItem(storageKey, JSON.stringify(data)); return true; }
        catch (e) { _metrics.errors++; console.error('[Transport L4] Save failed:', e); return false; }
    }

    function load(storageKey, merge = true) {
        _metrics.loads++;
        if (typeof localStorage === 'undefined') return false;
        try {
            const raw = localStorage.getItem(storageKey);
            if (!raw) return false;
            if (!merge) clear(true);
            setAll(JSON.parse(raw));
            _emit('load', { storageKey });
            return true;
        } catch (e) { console.error('[Transport L4] Load failed:', e); return false; }
    }





    function transaction(fn) {
        const snap = snapshot();
        try {
            fn({ get, set, has, del });
            _metrics.transactions++;
            _emit('transaction', { success: true });
        } catch (e) {
            _metrics.errors++;
            restore(snap, true);
            _emit('transaction', { success: false, error: e });
            throw e;
        }
    }







    function metrics() {
        return {
            ..._metrics,
            uptime: Date.now() - _metrics.startTime,
            throughput: (_metrics.sets + _metrics.gets) / ((Date.now() - _metrics.startTime) / 1000 || 1)
        };
    }

    function resetMetrics() {
        Object.keys(_metrics).forEach(k => {
            if (k !== 'startTime') _metrics[k] = 0;
        });
        _metrics.startTime = Date.now();
    }


    return Object.freeze({
        name:    'Transport Substrate (Reliable Delivery)',
        layer:   4,
        genesis: 'Form',
        surface: 'z=xy²',
        zxy2,

        set, get, has, del, clear, getAll, setAll,

        computed, watch,

        on, off, once,

        history, clearHistory, snapshot, restore, save, load, transaction,

        metrics, resetMetrics,

        stats: () => ({
            keys: _state.size,
            listeners: [..._listeners.values()].reduce((s, a) => s + a.length, 0),
            history: _history.length,
            ..._metrics
        }),


        below: () => typeof NetworkSubstrate !== 'undefined' ? NetworkSubstrate : null
    });
})();

if (typeof window !== 'undefined') window.TransportSubstrate = TransportSubstrate;
if (typeof module !== 'undefined') module.exports = TransportSubstrate;
